            if self.settings.compiler == "gcc":
                self.requires("mingw_installer/0.1@lasote/testing")
    def configure(self):
        if self.settings.os == "Windows":
            if self.settings.compiler == "gcc":
                self.options["mingw_installer"].version = self.settings.compiler.version
```
